import import_declare_test

import sys
import json

from splunklib import modularinput as smi

import os
import traceback
import requests
from solnlib import conf_manager
from solnlib import log
from solnlib.modular_input import checkpointer
from splunktaucclib.modinput_wrapper import base_modinput as base_mi

import github_repository_helper

bin_dir = os.path.basename(__file__)
app_name = os.path.basename(os.path.dirname(os.getcwd()))

class ModInputGithubRepository(base_mi.BaseModInput):

    def __init__(self):
        use_single_instance = False
        super(ModInputGithubRepository, self).__init__(app_name, "github_repository", use_single_instance)
        self.global_checkbox_fields = None

    def get_scheme(self):
        scheme = smi.Scheme('GitHub Audit')
        scheme.description = 'GitHub Audit modular input'
        scheme.use_external_validation = True
        scheme.streaming_mode_xml = True
        scheme.use_single_instance = False

        scheme.add_argument(
            smi.Argument(
                'name',
                title='Name',
                description='Name',
                required_on_create=True
            )
        )
        return scheme

    def validate_input(self, definition):
        return github_repository_helper.validate_input(self, definition)

    def get_app_name(self):
        return app_name

    def stream_events(self, ew):
        return github_repository_helper.collect_events(self, ew)

    def get_account_fields(self):
        account_fields = []
        return account_fields

    def get_checkbox_fields(self):
        checkbox_fields = []
        return checkbox_fields

    def get_global_checkbox_fields(self):
        if self.global_checkbox_fields is None:
            checkbox_name_file = os.path.join(bin_dir, 'global_checkbox_param.json')
            try:
                if os.path.isfile(checkbox_name_file):
                    with open(checkbox_name_file, 'r') as fp:
                        self.global_checkbox_fields = json.load(fp)
                else:
                    self.global_checkbox_fields = []
            except Exception as e:
                self.log_error('Get exception when loading global checkbox parameter names. ' + str(e))
                self.global_checkbox_fields = []
        return self.global_checkbox_fields


if __name__ == '__main__':
    exit_code = ModInputGithubRepository().run(sys.argv)
    sys.exit(exit_code)
